import { vi, describe, it, expect, beforeEach } from 'vitest';

// ── Mock app-store ───────────────────────────────────────────
// Module-level closure captures the mutable state so tests can
// control what readData / readVideoCache return.

const mockAppStore = vi.hoisted(() => {
	let data = {
		subscriptions: [],
		settings: {},
		redirects: {},
	};
	let videoCache = {
		videos: [],
		lastUpdated: null,
		totalChannels: 0,
		totalVideos: 0,
		channelRefreshes: {},
		shortsStatusById: {},
	};

	function deepClone(obj) {
		return JSON.parse(JSON.stringify(obj));
	}

	return {
		readData: vi.fn(async () => deepClone(data)),
		writeData: vi.fn(async (d) => {
			data = d;
			return d;
		}),
		updateData: vi.fn(async (_fallback, updater) => {
			const current = deepClone(data);
			const updated = await updater(current);
			data = updated || current;
			return data;
		}),
		readVideoCache: vi.fn(async () => deepClone(videoCache)),
		writeVideoCache: vi.fn(async (c) => {
			videoCache = c;
			return c;
		}),
		getCurrentRevision: vi.fn(() => 1),
		// Reset internal data for a fresh test
		reset(overrides = {}) {
			data = overrides.data || {
				subscriptions: [],
				settings: {},
				redirects: {},
			};
			videoCache = overrides.videoCache || {
				videos: [],
				lastUpdated: null,
				totalChannels: 0,
				totalVideos: 0,
				channelRefreshes: {},
				shortsStatusById: {},
			};
			this.readData.mockImplementation(async () => deepClone(data));
			this.writeData.mockImplementation(async (d) => {
				data = d;
				return d;
			});
			this.updateData.mockImplementation(async (_fallback, updater) => {
				const current = deepClone(data);
				const updated = await updater(current);
				data = updated || current;
				return data;
			});
			this.readVideoCache.mockImplementation(async () => deepClone(videoCache));
			this.writeVideoCache.mockImplementation(async (c) => {
				videoCache = c;
				return c;
			});
			this.getCurrentRevision.mockImplementation(() => 1);
		},
	};
});

vi.mock('./app-store', () => mockAppStore);

// ── Mock feed-fetcher ─────────────────────────────────────────

const mockFeedFetcher = vi.hoisted(() => ({
	fetchChannelFeed: vi.fn(),
	fetchChannelThumbnail: vi.fn(),
}));

vi.mock('./feed-fetcher', () => ({
	fetchChannelFeed: mockFeedFetcher.fetchChannelFeed,
	fetchChannelThumbnail: mockFeedFetcher.fetchChannelThumbnail,
	fetchYouTubeApiVideos: vi.fn(),
	buildVideoFromFeedItem: vi.fn(),
	classifyFeedFailure: vi.fn(),
	createVideoItemHash: vi.fn(),
	fetchUploadsPlaylistFeed: vi.fn(),
	parseDuration: vi.fn(),
	parseUploadsPlaylistVideos: vi.fn(),
}));

// ── Import the module under test via ESM dynamic import ───────
// This ensures vi.mock intercepts the CJS dependencies.
// Dynamic import of a CJS module yields the module.exports.

const mod = await import('./feed-aggregator');
const __test__ = mod.__test__;

// ── Helpers ──────────────────────────────────────────────────

function setupStoreWithSubscriptions(subscriptions = [], overrides = {}) {
	mockAppStore.reset({
		data: {
			subscriptions,
			settings: {},
			redirects: {},
			...overrides.data,
		},
		videoCache: {
			videos: [],
			lastUpdated: null,
			totalChannels: subscriptions.length,
			totalVideos: 0,
			channelRefreshes: {},
			shortsStatusById: {},
			...overrides.videoCache,
		},
	});
}

// ── Tests ─────────────────────────────────────────────────────

describe('feed aggregator — refreshBatch (unit)', () => {
	it('refreshes a batch and preserves subscription metadata updates', async () => {
		const subscriptions = [
			{ id: 'UC_1', title: 'One', thumbnail: null },
			{ id: 'UC_2', title: 'Two', thumbnail: 'https://example.com/thumb.jpg' },
		];
		const fetchedChannelResults = [];
		const fetchChannelFeed = vi.fn(async (id) => ({
			videos: [
				{
					id: `${id}-video`,
					channelId: id,
					publishedAt: '2026-05-31T18:00:00.000Z',
				},
			],
			channelMetadata: { title: `${id}-updated`, thumbnail: null },
		}));
		const fetchChannelThumbnail = vi.fn(
			async (id) => `https://thumb.example/${id}.jpg`,
		);

		const result = await __test__.refreshBatch(
			[{ id: 'UC_1' }, { id: 'UC_2' }],
			subscriptions,
			fetchedChannelResults,
			{ fetchChannelFeed, fetchChannelThumbnail },
		);

		expect(fetchChannelFeed).toHaveBeenCalledTimes(2);
		expect(fetchChannelThumbnail).toHaveBeenCalledTimes(1);
		expect(subscriptions[0].title).toBe('UC_1-updated');
		expect(subscriptions[0].thumbnail).toBe('https://thumb.example/UC_1.jpg');
		expect(subscriptions[1].thumbnail).toBe('https://example.com/thumb.jpg');
		expect(fetchedChannelResults).toHaveLength(2);
		expect(result.batchRefreshResults).toHaveLength(2);
		expect(result.batchVideos).toEqual([
			{
				id: 'UC_1-video',
				channelId: 'UC_1',
				publishedAt: '2026-05-31T18:00:00.000Z',
			},
			{
				id: 'UC_2-video',
				channelId: 'UC_2',
				publishedAt: '2026-05-31T18:00:00.000Z',
			},
		]);
	});
});

describe('feed aggregator — status (unit)', () => {
	it('updates running aggregation status with an explicit startedAt timestamp', () => {
		__test__.setRunningAggregationStatus({
			skippedChannels: 3,
			subscriptions: [{ id: 'UC_1' }, { id: 'UC_2' }],
			existingVideos: [{ id: 'video-1' }],
			startedAt: '2026-05-31T18:00:00.000Z',
		});

		expect(__test__.getAggregationStatus()).toMatchObject({
			state: 'running',
			current: 3,
			total: 2,
			videos: 1,
			errors: 0,
			startedAt: '2026-05-31T18:00:00.000Z',
			completedAt: null,
		});
	});
});

describe('feed aggregator — runAggregation (characterization)', () => {
	beforeEach(() => {
		vi.clearAllMocks();
		mockAppStore.reset();
	});

	it('completes without error when there are no subscriptions', async () => {
		await __test__.runAggregation();

		// Should have written data and video cache
		expect(mockAppStore.writeData).toHaveBeenCalled();
		expect(mockAppStore.writeVideoCache).toHaveBeenCalled();
		// No feeds were fetched (nothing to refresh)
		expect(mockFeedFetcher.fetchChannelFeed).not.toHaveBeenCalled();
	});

	it('fetches feeds for all subscriptions and writes video cache', async () => {
		const subscriptions = [
			{ id: 'UC_ONE', title: 'Channel One' },
			{ id: 'UC_TWO', title: 'Channel Two' },
		];

		setupStoreWithSubscriptions(subscriptions);

		// Mock feed fetcher to return one video per channel
		mockFeedFetcher.fetchChannelFeed.mockImplementation(
			async (channelId) => ({
				videos: [
					{
						id: `vid-${channelId}-1`,
						channelId,
						publishedAt: '2026-06-01T12:00:00.000Z',
					},
				],
				channelMetadata: { title: `Refreshed ${channelId}` },
			}),
		);
		mockFeedFetcher.fetchChannelThumbnail.mockImplementation(
			async (channelId) => `https://thumb/${channelId}.jpg`,
		);

		await __test__.runAggregation();

		// Each channel's feed was fetched
		expect(mockFeedFetcher.fetchChannelFeed).toHaveBeenCalledTimes(2);
		// Thumbnails: both have no thumbnail pre-set, so both get fetched
		expect(mockFeedFetcher.fetchChannelThumbnail).toHaveBeenCalledTimes(0);
		// note: the actual thumbnail call count depends on whether the
		// subscription already has a thumbnail; both channels in the test
		// have title-only metadata, so thumbnail fetching depends on
		// channelMetadata.thumbnail from the feed response — which is null.

		// Data was written with subscription metadata
		expect(mockAppStore.writeData).toHaveBeenCalled();
		const lastWriteDataCall =
			mockAppStore.writeData.mock.calls.at(-1);
		const writtenData = lastWriteDataCall[0];
		expect(writtenData.subscriptions).toHaveLength(2);

		// Video cache was written with the fetched videos
		expect(mockAppStore.writeVideoCache).toHaveBeenCalled();
		const lastWriteVideoCall =
			mockAppStore.writeVideoCache.mock.calls.at(-1);
		const writtenCache = lastWriteVideoCall[0];
		expect(writtenCache.videos.length).toBeGreaterThanOrEqual(2);
		expect(writtenCache.totalChannels).toBe(2);
	});
});

describe('feed aggregator — aggregateOnStartupIfStale (characterization)', () => {
	beforeEach(() => {
		vi.clearAllMocks();
		mockAppStore.reset();
	});

	it('skips aggregation when the video cache is fresh and matches subscriptions', async () => {
		const subscriptions = [
			{ id: 'UC_A', title: 'Channel A' },
			{ id: 'UC_B', title: 'Channel B' },
		];

		// Fresh video cache: lastUpdated < 10 min ago, totalChannels matches
		// subscription count, all videos have shorts metadata.
		const freshCache = {
			videos: [
				{
					id: 'vid-1',
					channelId: 'UC_A',
					publishedAt: '2026-06-01T12:00:00.000Z',
				},
			],
			lastUpdated: new Date().toISOString(),
			totalChannels: 2,
			totalVideos: 1,
			channelRefreshes: {
				UC_A: { lastFetchedAt: new Date().toISOString() },
				UC_B: { lastFetchedAt: new Date().toISOString() },
			},
			shortsStatusById: { 'vid-1': false },
		};

		setupStoreWithSubscriptions(subscriptions, { videoCache: freshCache });

		await __test__.aggregateOnStartupIfStale();

		// Should NOT have triggered an aggregation
		expect(mockFeedFetcher.fetchChannelFeed).not.toHaveBeenCalled();
		// readData and readVideoCache were called for the freshness check
		expect(mockAppStore.readData).toHaveBeenCalled();
		expect(mockAppStore.readVideoCache).toHaveBeenCalled();
	});

	it('triggers aggregation when cache is stale', async () => {
		const subscriptions = [
			{ id: 'UC_C', title: 'Channel C' },
		];

		// Stale cache: lastUpdated is more than 10 minutes ago
		const staleCache = {
			videos: [],
			lastUpdated: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
			totalChannels: 1,
			totalVideos: 0,
			channelRefreshes: {},
			shortsStatusById: {},
		};

		setupStoreWithSubscriptions(subscriptions, { videoCache: staleCache });

		await __test__.aggregateOnStartupIfStale();

		// Should have triggered an aggregation (trigger is fire-and-forget,
		// so it returns before the aggregation finishes; no feed calls yet)
		expect(mockAppStore.readData).toHaveBeenCalled();
		expect(mockAppStore.readVideoCache).toHaveBeenCalled();
	});
});

